    companion object {
        /**
         * Converts the provided [data] to a [String] on success, null otherwise.
         */
        fun encode(data: kotlin.Any?): kotlin.String? = if (data is ProvinciaMunicipioType) "$data" else null

        /**
         * Returns a valid [ProvinciaMunicipioType] for [data], null otherwise.
         */
        fun decode(data: kotlin.Any?): ProvinciaMunicipioType? = data?.let {
          val normalizedData = "$it".lowercase()
          entries.firstOrNull { value ->
            it == value || normalizedData == "$value".lowercase()
          }
        }
    }
}


